const useResolveTriggerType=e=>("string"==typeof e?[e]:e).reduce((e,r)=>{switch(r){case"click":return e.triggerOnClick=!0,e;case"hover":return e.triggerOnHover=!0,e;case"focus":return e.triggerOnFocus=!0,e;case"manual":return e}},{triggerOnFocus:!1,triggerOnClick:!1,triggerOnHover:!1});export{useResolveTriggerType};